-- ===== 042_reviews_system.sql =====

-- 멘토 리뷰 (학생 작성, 멘토 답글 1회, 관리자 숨김)
create table if not exists public.reviews (
  id uuid primary key default gen_random_uuid(),
  mentor_id uuid not null references public.mentor_profiles (user_id) on delete cascade,
  student_id uuid not null references auth.users (id) on delete cascade,
  subscription_count integer not null,
  rating integer not null check (rating between 1 and 5),
  content text not null,
  mentor_reply text,
  mentor_replied_at timestamptz,
  is_hidden boolean not null default false,
  created_at timestamptz not null default now(),
  constraint reviews_one_per_pair unique (mentor_id, student_id)
);

-- [bundle compatibility]
-- 004_p0_cash_disputes_admin_draft.sql creates an early reviews table with
-- author_id/body. 042_reviews_system.sql expects student_id/content. On a
-- blank setup that runs bundle_1 first, CREATE TABLE IF NOT EXISTS above does
-- not add the later columns, so normalize the table shape before indexes/RLS.
alter table public.reviews
  add column if not exists student_id uuid references auth.users (id) on delete cascade,
  add column if not exists subscription_count integer not null default 0,
  add column if not exists content text,
  add column if not exists mentor_reply text,
  add column if not exists mentor_replied_at timestamptz,
  add column if not exists is_hidden boolean not null default false;

update public.reviews
set student_id = author_id
where student_id is null and author_id is not null;

update public.reviews
set content = body
where content is null and body is not null;

update public.reviews
set content = ''
where content is null;

do $$
begin
  if exists (
    select 1
    from information_schema.columns
    where table_schema = 'public'
      and table_name = 'reviews'
      and column_name = 'student_id'
      and is_nullable = 'YES'
  )
  and not exists (select 1 from public.reviews where student_id is null) then
    alter table public.reviews alter column student_id set not null;
  end if;
end $$;

do $$
begin
  if exists (
    select 1
    from information_schema.columns
    where table_schema = 'public'
      and table_name = 'reviews'
      and column_name = 'content'
      and is_nullable = 'YES'
  )
  and not exists (select 1 from public.reviews where content is null) then
    alter table public.reviews alter column content set not null;
  end if;
end $$;

create unique index if not exists idx_reviews_one_per_pair_compat
  on public.reviews (mentor_id, student_id)
  where student_id is not null;

create index if not exists idx_reviews_mentor_created on public.reviews (mentor_id, created_at desc);
create index if not exists idx_reviews_student on public.reviews (student_id);

alter table public.reviews enable row level security;

-- 공개 읽기: 숨김 제외 (본인·멘토·관리자는 숨김 포함 조회)
drop policy if exists "reviews_select_public" on public.reviews;
create policy "reviews_select_public" on public.reviews
  for select
  using (
    is_hidden = false
    or (select auth.uid()) = student_id
    or (select auth.uid()) = mentor_id
    or exists (
      select 1 from public.users u
      where u.id = (select auth.uid()) and u.role = 'admin'
    )
  );

-- 학생 작성 (자격은 서버/API에서 검증)
drop policy if exists "reviews_insert_student" on public.reviews;
create policy "reviews_insert_student" on public.reviews
  for insert to authenticated
  with check ((select auth.uid()) = student_id);

-- 멘토 답글 (본인 리뷰에만)
drop policy if exists "reviews_update_mentor_reply" on public.reviews;
create policy "reviews_update_mentor_reply" on public.reviews
  for update to authenticated
  using ((select auth.uid()) = mentor_id)
  with check ((select auth.uid()) = mentor_id);

-- 관리자 숨김/복구
drop policy if exists "reviews_admin_moderate" on public.reviews;
create policy "reviews_admin_moderate" on public.reviews
  for update to authenticated
  using (
    exists (
      select 1 from public.users u
      where u.id = (select auth.uid()) and u.role = 'admin'
    )
  )
  with check (
    exists (
      select 1 from public.users u
      where u.id = (select auth.uid()) and u.role = 'admin'
    )
  );

comment on table public.reviews is '멘토 리뷰: 동일 멘토 2회+ 구독 학생만 작성, 수정 불가, 멘토 답글 1회';


-- ===== 033_p1_admin_reviews_moderation.sql =====

-- [의존 순서] 이 파일은 042_reviews_system.sql 이후 적용할 것
-- [번호 충돌] 접두 033 — 동일 번호: 033_question_threads_topic.sql (이 파일: reviews 관리자 모더레이션)
-- =============================================================================
-- 033_p1_admin_reviews_moderation.sql
-- 목적: public.reviews 운영 조치 컬럼 + 공개 SELECT 제한(숨김·블라인드 비노출) + 관리자 전체 조회
-- 적용: 저장소 전용. Supabase SQL Editor에 수동 적용. (자동 배포 없음)
-- 선행: public.reviews, public.is_admin() (003 등), auth.users
-- 주의: 기존 rev_ins / rev_update_own 등 쓰기 정책은 변경하지 않습니다.
-- =============================================================================

-- —— 컬럼( idempotent ) ——
alter table if exists public.reviews
  add column if not exists is_hidden boolean not null default false;

alter table if exists public.reviews
  add column if not exists is_blinded boolean not null default false;

alter table if exists public.reviews
  add column if not exists moderation_state text not null default 'visible';

alter table if exists public.reviews
  add column if not exists moderated_at timestamptz;

alter table if exists public.reviews
  add column if not exists moderated_by uuid null references auth.users (id) on delete set null;

comment on column public.reviews.is_hidden is '관리자·운영: 공개 목록에서 제외.';
comment on column public.reviews.is_blinded is '관리자·운영: 블라인드(비노출).';
comment on column public.reviews.moderation_state is '운영 상태(예: visible, reviewed).';
comment on column public.reviews.moderated_at is '마지막 운영 조치 시각.';
comment on column public.reviews.moderated_by is '마지막 운영 조치자 auth.users.id.';

alter table if exists public.reviews enable row level security;

-- —— SELECT: 004 등에서 rev_select 가 using(true) 이면 숨김이 무력화되므로 제거 후 재정의 ——
drop policy if exists rev_select on public.reviews;
drop policy if exists reviews_select_public_visible on public.reviews;
drop policy if exists reviews_select_admin on public.reviews;

-- 익명·일반 로그인: 공개로 볼 수 있는 리뷰만 (컬럼은 위에서 항상 존재)
create policy reviews_select_public_visible
  on public.reviews
  for select
  to anon, authenticated
  using (
    coalesce(is_hidden, false) = false
    and coalesce(is_blinded, false) = false
  );

-- 관리자: 전체 행 조회(관리 콘솔·검수). is_admin() = public.users.role = 'admin'
create policy reviews_select_admin
  on public.reviews
  for select
  to authenticated
  using ((select public.is_admin()) = true);

-- rev_ins / rev_update_own 등 기존 정책은 그대로 둡니다.


-- ===== 043_p1_accept_order_settlement_atomic_rpc.sql =====

-- P1: 학생 납품 수락 + 정산 예정 insert — 단일 트랜잭션 (service_role 전용 RPC)
-- 선행: 003(custom_request_orders), 013(custom_order_settlement_items), 015(dispute trigger)
-- idempotent: CREATE OR REPLACE

-- ---------------------------------------------------------------------------
-- Helpers
-- ---------------------------------------------------------------------------
create or replace function public._positive_int_from_numeric(v numeric)
returns integer
language sql
immutable
as $$
  select case when v is not null and v > 0 then floor(v)::integer else null end;
$$;

create or replace function public._order_primary_status_norm(o public.custom_request_orders)
returns text
language sql
immutable
as $$
  select lower(trim(coalesce(
    nullif(trim((o).status), ''),
    nullif(trim((o).state), ''),
    nullif(trim((o).order_status), ''),
    nullif(trim((o).stage), ''),
    ''
  )));
$$;

-- 금액 컬럼 출처: 003_p0_custom_request_draft.sql (custom_request_orders / custom_request_applications)
create or replace function public._pick_custom_order_gross_won(
  o public.custom_request_orders,
  app public.custom_request_applications
)
returns integer
language sql
stable
as $$
  select coalesce(
    public._positive_int_from_numeric((o).agreed_price),
    public._positive_int_from_numeric((o).proposed_price),
    public._positive_int_from_numeric((o).price),
    public._positive_int_from_numeric((o).amount),
    public._positive_int_from_numeric((app).proposed_price),
    public._positive_int_from_numeric((app).bid_amount),
    public._positive_int_from_numeric((app).price)
  );
$$;

-- ---------------------------------------------------------------------------
-- accept_custom_order_deliverable_atomic
-- ---------------------------------------------------------------------------
create or replace function public.accept_custom_order_deliverable_atomic(
  p_order_id uuid,
  p_student_id uuid,
  p_require_payment boolean default true
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $function$
declare
  o public.custom_request_orders%rowtype;
  app public.custom_request_applications%rowtype;
  v_norm text;
  v_pay text;
  v_dispute_cnt integer;
  v_deliverable_cnt integer;
  v_existing_settlement uuid;
  v_gross integer;
  v_platform_fee integer;
  v_mentor_amount integer;
  v_settlement_id uuid;
  v_settlement_created boolean := false;
  v_now timestamptz := now();
  v_fee_rate numeric := 0.20;
begin
  if p_order_id is null then
    return jsonb_build_object('ok', false, 'message', 'orderId가 필요합니다.');
  end if;
  if p_student_id is null then
    return jsonb_build_object('ok', false, 'message', '학생 ID가 필요합니다.');
  end if;

  select * into o
  from public.custom_request_orders
  where id = p_order_id
  for update;

  if not found then
    return jsonb_build_object('ok', false, 'message', '주문을 찾을 수 없어요.');
  end if;

  if o.student_id is distinct from p_student_id then
    return jsonb_build_object('ok', false, 'message', '의뢰자(학생) 본인만 납품을 수락할 수 있습니다.');
  end if;

  v_pay := lower(trim(coalesce(nullif(trim(o.payment_status), ''), '')));
  if p_require_payment and v_pay is distinct from 'paid' then
    return jsonb_build_object('ok', false, 'message', '결제가 완료되지 않은 주문은 수락할 수 없습니다.');
  end if;

  if o.completed_at is not null
     or o.closed_at is not null
     or o.finished_at is not null
     or lower(trim(coalesce(o.status, ''))) in (
       'completed','accepted','closed','finished','cancelled','canceled',
       'refunded','rejected','done','resolved','dispute_resolved'
     )
     or lower(trim(coalesce(o.state, ''))) in (
       'completed','accepted','closed','finished','cancelled','canceled',
       'refunded','rejected','done','resolved','dispute_resolved'
     )
     or lower(trim(coalesce(o.order_status, ''))) in (
       'completed','accepted','closed','finished','cancelled','canceled',
       'refunded','rejected','done','resolved','dispute_resolved'
     )
  then
    return jsonb_build_object('ok', false, 'message', '이미 완료된 주문입니다.');
  end if;

  v_norm := public._order_primary_status_norm(o);
  if v_norm = '' then
    return jsonb_build_object('ok', false, 'message', '주문 상태를 확인할 수 없어 수락할 수 없습니다.');
  end if;

  if v_norm not in (
    'delivered','delivered_pending_review','waiting_review','pending_review',
    'redelivered','delivery_submitted','in_review'
  ) then
    return jsonb_build_object(
      'ok', false,
      'message', format('현재 상태(%s)에서는 납품 수락을 할 수 없습니다.', v_norm)
    );
  end if;

  select count(*)::integer into v_dispute_cnt
  from public.disputes d
  where d.custom_request_order_id = p_order_id
    and d.status in ('open', 'under_review', 'escalated');

  if v_dispute_cnt > 0 then
    return jsonb_build_object('ok', false, 'message', '진행 중인 분쟁이 있어 납품 수락을 할 수 없습니다.');
  end if;

  select count(*)::integer into v_deliverable_cnt
  from public.custom_order_deliverables d
  where d.custom_request_order_id = p_order_id;

  if v_deliverable_cnt < 1 then
    return jsonb_build_object('ok', false, 'message', '등록된 납품이 없어 수락할 수 없습니다.');
  end if;

  select id into v_existing_settlement
  from public.custom_order_settlement_items s
  where s.custom_request_order_id = p_order_id;

  select a.* into app
  from public.custom_request_applications a
  where a.id = coalesce(o.application_id, o.custom_request_application_id, o.selected_application_id)
  limit 1;

  if v_existing_settlement is null then
    v_gross := public._pick_custom_order_gross_won(o, app);
    if v_gross is not null and v_gross > 0 then
      v_platform_fee := floor(v_gross * v_fee_rate)::integer;
      v_mentor_amount := v_gross - v_platform_fee;

      insert into public.custom_order_settlement_items (
        custom_request_order_id,
        mentor_id,
        student_id,
        gross_amount,
        platform_fee_amount,
        mentor_amount,
        fee_rate,
        status
      ) values (
        p_order_id,
        o.mentor_id,
        o.student_id,
        v_gross,
        v_platform_fee,
        v_mentor_amount,
        v_fee_rate,
        'pending'
      )
      returning id into v_settlement_id;

      v_settlement_created := true;
    end if;
  else
    v_settlement_id := v_existing_settlement;
  end if;

  update public.custom_request_orders
  set
    status = 'completed',
    state = 'completed',
    order_status = 'completed',
    accepted_at = coalesce(accepted_at, v_now),
    completed_at = coalesce(completed_at, v_now),
    updated_at = v_now
  where id = p_order_id;

  return jsonb_build_object(
    'ok', true,
    'settlement_created', v_settlement_created,
    'settlement_id', v_settlement_id,
    'gross', v_gross,
    'fee_rate', v_fee_rate
  );
exception
  when others then
    if sqlstate = '23505' then
      -- unique settlement per order — treat as idempotent success path
      select id into v_existing_settlement
      from public.custom_order_settlement_items s
      where s.custom_request_order_id = p_order_id;

      update public.custom_request_orders
      set
        status = 'completed',
        state = 'completed',
        order_status = 'completed',
        accepted_at = coalesce(accepted_at, v_now),
        completed_at = coalesce(completed_at, v_now),
        updated_at = v_now
      where id = p_order_id;

      return jsonb_build_object(
        'ok', true,
        'settlement_created', false,
        'settlement_id', v_existing_settlement,
        'reason', 'already_exists'
      );
    end if;
    raise;
end;
$function$;

comment on function public.accept_custom_order_deliverable_atomic(uuid, uuid, boolean) is
  'P1: Student deliverable accept — order completed + settlement row in one transaction. service_role only; app validates student session then passes p_student_id.';

revoke all on function public.accept_custom_order_deliverable_atomic(uuid, uuid, boolean) from public;
grant execute on function public.accept_custom_order_deliverable_atomic(uuid, uuid, boolean) to service_role;


