-- ===== 045_review_eligibility_guard.sql =====

-- =============================================================================
-- 045_review_eligibility_guard.sql
-- 목적: reviews INSERT RLS — 동일 멘토에 결제 완료 구독 2회 이상일 때만 허용
-- 선행: 004_p0_cash_disputes_admin_draft.sql (reviews.author_id), 002_p0 (subscriptions.student_id)
-- 적용: Supabase SQL Editor 수동 적용
-- =============================================================================

create or replace function public.check_review_eligibility(
  p_mentor_id uuid,
  p_student_id uuid
) returns boolean
language plpgsql
security definer
set search_path = public
as $$
declare
  paid_count integer;
  ledger_paid integer;
begin
  if p_mentor_id is null or p_student_id is null then
    return false;
  end if;

  -- subscriptions.payment_id → payments (002 스키마; payments.subscription_id 없음)
  select count(*)::integer
  into paid_count
  from public.subscriptions s
  inner join public.payments p on p.id = s.payment_id
  where s.student_id = p_student_id
    and s.mentor_id = p_mentor_id
    and lower(trim(p.status)) in (
      'paid', 'succeeded', 'completed', 'complete', 'success',
      'captured', 'escrowed', 'paid_out'
    )
    and p.amount > 0
    and coalesce(lower(trim(s.plan_tier)), '') not in ('free', 'trial')
    and coalesce(lower(trim(s.plan_tier)), '') not like '%trial%';

  if paid_count >= 2 then
    return true;
  end if;

  -- 캐시 구독 차감( payment_id 없음 ) 대체 판정
  select count(*)::integer
  into ledger_paid
  from public.subscriptions s
  where s.student_id = p_student_id
    and s.mentor_id = p_mentor_id
    and exists (
      select 1
      from public.cash_ledger cl
      where cl.user_id = p_student_id
        and cl.ref_type = 'subscriptions'
        and cl.ref_id = s.id
        and cl.delta_cents < 0
    );

  return ledger_paid >= 2;
end;
$$;

revoke all on function public.check_review_eligibility(uuid, uuid) from public, anon;
grant execute on function public.check_review_eligibility(uuid, uuid) to authenticated;

comment on function public.check_review_eligibility(uuid, uuid) is
  '리뷰 작성 자격: 동일 멘토 paid 구독 2회+ (payments 또는 cash_ledger 차감)';

drop policy if exists "reviews_insert_author" on public.reviews;
drop policy if exists "reviews_insert_student" on public.reviews;

create policy "reviews_insert_student" on public.reviews
  for insert
  to authenticated
  with check (
    (select auth.uid()) = author_id
    and public.check_review_eligibility(mentor_id, (select auth.uid()))
  );


-- ===== 046_free_question_usage_db_guard.sql =====

-- 046_free_question_usage_db_guard.sql
-- 무료 질문권 TOCTOU 방지: free_question_usage INSERT 시 DB 레벨 한도 강제
-- 선행: 044_free_question_usage.sql

create or replace function public.check_free_question_usage_limits()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  per_mentor_count integer;
  total_count integer;
begin
  select count(*)::integer
  into per_mentor_count
  from public.free_question_usage
  where student_id = new.student_id
    and mentor_id = new.mentor_id;

  if per_mentor_count >= 3 then
    raise exception 'FREE_QUESTION_PER_MENTOR_LIMIT'
      using errcode = 'P0001';
  end if;

  select count(*)::integer
  into total_count
  from public.free_question_usage
  where student_id = new.student_id;

  if total_count >= 15 then
    raise exception 'FREE_QUESTION_TOTAL_LIMIT'
      using errcode = 'P0002';
  end if;

  return new;
end;
$$;

drop trigger if exists trg_free_question_usage_limits on public.free_question_usage;
create trigger trg_free_question_usage_limits
  before insert on public.free_question_usage
  for each row
  execute function public.check_free_question_usage_limits();

revoke all on function public.check_free_question_usage_limits() from public, anon;
grant execute on function public.check_free_question_usage_limits() to authenticated;


-- ===== 047_active_dispute_settlement_block_trigger.sql =====

-- =============================================================================
-- 047_active_dispute_settlement_block_trigger.sql
-- Supabase SQL Editor: "VERIFY - Active Dispute Blocking Trigger" 이관본
-- 목적: 진행 중 분쟁(open|under_review|escalated) 시 custom_order_settlement_items INSERT 차단
-- 선행: 004_p0_cash_disputes_admin_draft.sql (disputes), 013_p0_custom_order_settlement_items.sql
-- idempotent: CREATE OR REPLACE FUNCTION + DROP TRIGGER IF EXISTS
-- =============================================================================

create or replace function public.trg_block_settlement_on_active_dispute()
returns trigger
language plpgsql
security invoker
set search_path = public
as $fn$
declare
  v_cnt integer;
begin
  if new.custom_request_order_id is null then
    return new;
  end if;

  select count(*)::integer
    into v_cnt
  from public.disputes d
  where d.custom_request_order_id = new.custom_request_order_id
    and d.status in ('open', 'under_review', 'escalated');

  if v_cnt > 0 then
    raise exception 'settlement insert blocked: active dispute for order %', new.custom_request_order_id
      using errcode = 'P0001',
            hint = '진행 중인 분쟁이 있으면 정산 예정을 추가할 수 없습니다.';
  end if;

  return new;
end;
$fn$;

drop trigger if exists trg_cosi_prevent_active_dispute on public.custom_order_settlement_items;
create trigger trg_cosi_prevent_active_dispute
  before insert on public.custom_order_settlement_items
  for each row
  execute function public.trg_block_settlement_on_active_dispute();

