-- ===== 054_p0_custom_order_escrow_hold.sql =====

-- P0: 맞춤의뢰 예치(에스크로 hold) — 학생 캐시 차감 + cash_ledger append-only
-- 선행: 004_p0_cash_disputes_admin_draft.sql (cash_wallets, cash_ledger)
--        003_p0_custom_request_draft.sql (custom_request_orders)
-- idempotent: CREATE OR REPLACE
--
-- 호출: service_role (서버) 전용. authenticated/anon GRANT 금지.
-- idempotency_key: 'cr_hold_' || p_order_id
-- reason: custom_order_escrow_hold | ref_type: custom_request_orders

create or replace function public.record_custom_order_escrow_hold(
  p_student_id uuid,
  p_order_id uuid,
  p_amount_cents bigint
)
returns void
language plpgsql
security definer
set search_path = public
as $function$
declare
  v_idem text := 'cr_hold_' || p_order_id::text;
  v_new_ledger_id uuid;
  v_wu int;
begin
  if p_student_id is null or p_order_id is null then
    raise exception 'p_student_id and p_order_id are required';
  end if;

  if p_amount_cents is null or p_amount_cents <= 0 then
    raise exception 'p_amount_cents must be a positive amount';
  end if;

  if p_amount_cents > 1000000000 then
    raise exception 'p_amount_too_large';
  end if;

  insert into public.cash_ledger (user_id, delta_cents, reason, ref_type, ref_id, idempotency_key)
  values (
    p_student_id,
    -p_amount_cents,
    'custom_order_escrow_hold',
    'custom_request_orders',
    p_order_id,
    v_idem
  )
  on conflict (idempotency_key) do nothing
  returning id into v_new_ledger_id;

  if v_new_ledger_id is null then
    return;
  end if;

  insert into public.cash_wallets (user_id, balance_cents)
  values (p_student_id, 0)
  on conflict (user_id) do nothing;

  update public.cash_wallets w
  set balance_cents = w.balance_cents - p_amount_cents
  where w.user_id = p_student_id
    and w.balance_cents >= p_amount_cents;
  get diagnostics v_wu = row_count;
  if coalesce(v_wu, 0) = 0 then
    raise exception 'CASH_INSUFFICIENT' using errcode = 'P0001';
  end if;
end;
$function$;

comment on function public.record_custom_order_escrow_hold(uuid, uuid, bigint) is
  'P0: Custom order escrow hold — student wallet debit + ledger (append-only). service_role only.';

revoke all on function public.record_custom_order_escrow_hold(uuid, uuid, bigint) from public;
revoke all on function public.record_custom_order_escrow_hold(uuid, uuid, bigint) from anon;
revoke all on function public.record_custom_order_escrow_hold(uuid, uuid, bigint) from authenticated;

grant execute on function public.record_custom_order_escrow_hold(uuid, uuid, bigint) to service_role;


-- ===== 055_p0_custom_order_escrow_payout.sql =====

-- P0: 맞춤의뢰 에스크로 2단계 — 납품 수락 시 멘토 지급 + settlement paid + payment_status paid
-- 선행: 043(accept_custom_order_deliverable_atomic), 054(record_custom_order_escrow_hold)
-- idempotent: CREATE OR REPLACE
--
-- 호출: service_role 전용. authenticated/anon GRANT 금지.
-- 멱등키: cr_payout_{order_id} (주문당 정산·지급 1회, uq_cosi_one_per_order 와 정합)
-- fee_rate: accept RPC·settlement insert 시 기존 0.20 유지(변경 금지)

-- ---------------------------------------------------------------------------
-- record_custom_order_escrow_payout
-- ---------------------------------------------------------------------------
create or replace function public.record_custom_order_escrow_payout(
  p_order_id uuid
)
returns void
language plpgsql
security definer
set search_path = public
as $function$
declare
  o public.custom_request_orders%rowtype;
  s public.custom_order_settlement_items%rowtype;
  v_idem text := 'cr_payout_' || p_order_id::text;
  v_mentor_cents bigint;
  v_hold_cents bigint;
  v_gross_cents bigint;
  v_new_ledger_id uuid;
  v_wu int;
  v_pay text;
  v_now timestamptz := now();
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;

  select * into o
  from public.custom_request_orders
  where id = p_order_id
  for update;

  if not found then
    raise exception 'ORDER_NOT_FOUND';
  end if;

  v_pay := lower(trim(coalesce(nullif(trim(o.payment_status), ''), '')));

  select * into s
  from public.custom_order_settlement_items
  where custom_request_order_id = p_order_id
  for update;

  if not found then
    raise exception 'SETTLEMENT_NOT_FOUND';
  end if;

  -- 이미 지급 완료 — 멱등 수리(주문 payment_status 만 escrowed→paid 보정)
  if s.status = 'paid' then
    if v_pay = 'escrowed' then
      update public.custom_request_orders
      set payment_status = 'paid', updated_at = v_now
      where id = p_order_id;
    end if;
    return;
  end if;

  if s.status not in ('pending', 'payable', 'on_hold') then
    raise exception 'SETTLEMENT_NOT_PAYABLE';
  end if;

  -- escrowed(정상) 또는 paid(부분 실패 수리) 만 지급. unpaid·legacy 무예치 차단.
  if v_pay not in ('escrowed', 'paid') then
    raise exception 'PAYMENT_NOT_ESCROWED';
  end if;

  -- 예치 hold 존재·금액 정합: hold cents == settlement gross(원)×100
  select abs(l.delta_cents) into v_hold_cents
  from public.cash_ledger l
  where l.idempotency_key = 'cr_hold_' || p_order_id::text
    and l.reason = 'custom_order_escrow_hold'
  limit 1;

  v_gross_cents := s.gross_amount::bigint * 100;

  if v_hold_cents is null then
    raise exception 'ESCROW_HOLD_MISSING';
  end if;

  if v_hold_cents <> v_gross_cents then
    raise exception 'ESCROW_HOLD_AMOUNT_MISMATCH';
  end if;

  -- mentor_amount: 원(integer) → cents(원×100). gross/ledger 와 동일 단위 규칙.
  v_mentor_cents := s.mentor_amount::bigint * 100;

  if v_mentor_cents is null or v_mentor_cents <= 0 then
    raise exception 'INVALID_MENTOR_AMOUNT';
  end if;

  if v_mentor_cents > 1000000000 then
    raise exception 'p_amount_too_large';
  end if;

  -- 플랫폼 수수료(gross − mentor_amount)는 별도 platform wallet ledger 없음 — hold 차감분에 implicit.

  insert into public.cash_ledger (user_id, delta_cents, reason, ref_type, ref_id, idempotency_key)
  values (
    s.mentor_id,
    v_mentor_cents,
    'custom_order_escrow_payout',
    'custom_request_orders',
    p_order_id,
    v_idem
  )
  on conflict (idempotency_key) do nothing
  returning id into v_new_ledger_id;

  if v_new_ledger_id is null then
    update public.custom_order_settlement_items
    set status = 'paid', paid_at = coalesce(paid_at, v_now), updated_at = v_now
    where id = s.id and status <> 'paid';

    update public.custom_request_orders
    set payment_status = 'paid', updated_at = v_now
    where id = p_order_id and payment_status = 'escrowed';

    return;
  end if;

  insert into public.cash_wallets (user_id, balance_cents)
  values (s.mentor_id, 0)
  on conflict (user_id) do nothing;

  update public.cash_wallets w
  set balance_cents = w.balance_cents + v_mentor_cents
  where w.user_id = s.mentor_id;
  get diagnostics v_wu = row_count;
  if coalesce(v_wu, 0) = 0 then
    raise exception 'CASH_WALLET_UPSERT_FAILED' using errcode = 'P0001';
  end if;

  update public.custom_order_settlement_items
  set status = 'paid', paid_at = v_now, updated_at = v_now
  where id = s.id;

  update public.custom_request_orders
  set payment_status = 'paid', updated_at = v_now
  where id = p_order_id;
end;
$function$;

comment on function public.record_custom_order_escrow_payout(uuid) is
  'P0: Custom order escrow payout — mentor wallet credit (mentor_amount×100 cents) + settlement paid. service_role only.';

revoke all on function public.record_custom_order_escrow_payout(uuid) from public;
revoke all on function public.record_custom_order_escrow_payout(uuid) from anon;
revoke all on function public.record_custom_order_escrow_payout(uuid) from authenticated;

grant execute on function public.record_custom_order_escrow_payout(uuid) to service_role;

-- ---------------------------------------------------------------------------
-- accept_custom_order_deliverable_atomic — escrowed 수락 허용 + payout 연동(동일 트랜잭션)
-- ---------------------------------------------------------------------------
create or replace function public.accept_custom_order_deliverable_atomic(
  p_order_id uuid,
  p_student_id uuid,
  p_require_payment boolean default true
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $function$
declare
  o public.custom_request_orders%rowtype;
  app public.custom_request_applications%rowtype;
  v_norm text;
  v_pay text;
  v_dispute_cnt integer;
  v_deliverable_cnt integer;
  v_existing_settlement uuid;
  v_gross integer;
  v_platform_fee integer;
  v_mentor_amount integer;
  v_settlement_id uuid;
  v_settlement_created boolean := false;
  v_payout_done boolean := false;
  v_now timestamptz := now();
  v_fee_rate numeric := 0.20;
begin
  if p_order_id is null then
    return jsonb_build_object('ok', false, 'message', 'orderId가 필요합니다.');
  end if;
  if p_student_id is null then
    return jsonb_build_object('ok', false, 'message', '학생 ID가 필요합니다.');
  end if;

  select * into o
  from public.custom_request_orders
  where id = p_order_id
  for update;

  if not found then
    return jsonb_build_object('ok', false, 'message', '주문을 찾을 수 없어요.');
  end if;

  if o.student_id is distinct from p_student_id then
    return jsonb_build_object('ok', false, 'message', '의뢰자(학생) 본인만 납품을 수락할 수 있습니다.');
  end if;

  v_pay := lower(trim(coalesce(nullif(trim(o.payment_status), ''), '')));
  -- escrowed(예치 완료) 또는 paid(멱등·수리) 만 허용. unpaid 등 레거시 무예치 차단.
  if p_require_payment and v_pay not in ('paid', 'escrowed') then
    return jsonb_build_object('ok', false, 'message', '결제(예치)가 완료되지 않은 주문은 수락할 수 없습니다.');
  end if;

  if o.completed_at is not null
     or o.closed_at is not null
     or o.finished_at is not null
     or lower(trim(coalesce(o.status, ''))) in (
       'completed','accepted','closed','finished','cancelled','canceled',
       'refunded','rejected','done','resolved','dispute_resolved'
     )
     or lower(trim(coalesce(o.state, ''))) in (
       'completed','accepted','closed','finished','cancelled','canceled',
       'refunded','rejected','done','resolved','dispute_resolved'
     )
     or lower(trim(coalesce(o.order_status, ''))) in (
       'completed','accepted','closed','finished','cancelled','canceled',
       'refunded','rejected','done','resolved','dispute_resolved'
     )
  then
    return jsonb_build_object('ok', false, 'message', '이미 완료된 주문입니다.');
  end if;

  v_norm := public._order_primary_status_norm(o);
  if v_norm = '' then
    return jsonb_build_object('ok', false, 'message', '주문 상태를 확인할 수 없어 수락할 수 없습니다.');
  end if;

  if v_norm not in (
    'delivered','delivered_pending_review','waiting_review','pending_review',
    'redelivered','delivery_submitted','in_review'
  ) then
    return jsonb_build_object(
      'ok', false,
      'message', format('현재 상태(%s)에서는 납품 수락을 할 수 없습니다.', v_norm)
    );
  end if;

  select count(*)::integer into v_dispute_cnt
  from public.disputes d
  where d.custom_request_order_id = p_order_id
    and d.status in ('open', 'under_review', 'escalated');

  if v_dispute_cnt > 0 then
    return jsonb_build_object('ok', false, 'message', '진행 중인 분쟁이 있어 납품 수락을 할 수 없습니다.');
  end if;

  select count(*)::integer into v_deliverable_cnt
  from public.custom_order_deliverables d
  where d.custom_request_order_id = p_order_id;

  if v_deliverable_cnt < 1 then
    return jsonb_build_object('ok', false, 'message', '등록된 납품이 없어 수락할 수 없습니다.');
  end if;

  select id into v_existing_settlement
  from public.custom_order_settlement_items s
  where s.custom_request_order_id = p_order_id;

  select a.* into app
  from public.custom_request_applications a
  where a.id = coalesce(o.application_id, o.custom_request_application_id, o.selected_application_id)
  limit 1;

  if v_existing_settlement is null then
    v_gross := public._pick_custom_order_gross_won(o, app);
    if v_gross is not null and v_gross > 0 then
      v_platform_fee := floor(v_gross * v_fee_rate)::integer;
      v_mentor_amount := v_gross - v_platform_fee;

      insert into public.custom_order_settlement_items (
        custom_request_order_id,
        mentor_id,
        student_id,
        gross_amount,
        platform_fee_amount,
        mentor_amount,
        fee_rate,
        status
      ) values (
        p_order_id,
        o.mentor_id,
        o.student_id,
        v_gross,
        v_platform_fee,
        v_mentor_amount,
        v_fee_rate,
        'pending'
      )
      returning id into v_settlement_id;

      v_settlement_created := true;
    end if;
  else
    v_settlement_id := v_existing_settlement;
  end if;

  update public.custom_request_orders
  set
    status = 'completed',
    state = 'completed',
    order_status = 'completed',
    accepted_at = coalesce(accepted_at, v_now),
    completed_at = coalesce(completed_at, v_now),
    updated_at = v_now
  where id = p_order_id;

  if v_settlement_id is not null then
    perform public.record_custom_order_escrow_payout(p_order_id);
    v_payout_done := true;
  end if;

  return jsonb_build_object(
    'ok', true,
    'settlement_created', v_settlement_created,
    'settlement_id', v_settlement_id,
    'gross', v_gross,
    'fee_rate', v_fee_rate,
    'payout_done', v_payout_done
  );
exception
  when others then
    if sqlstate = '23505' then
      select id into v_existing_settlement
      from public.custom_order_settlement_items s
      where s.custom_request_order_id = p_order_id;

      update public.custom_request_orders
      set
        status = 'completed',
        state = 'completed',
        order_status = 'completed',
        accepted_at = coalesce(accepted_at, v_now),
        completed_at = coalesce(completed_at, v_now),
        updated_at = v_now
      where id = p_order_id;

      if v_existing_settlement is not null then
        perform public.record_custom_order_escrow_payout(p_order_id);
        v_payout_done := true;
      end if;

      return jsonb_build_object(
        'ok', true,
        'settlement_created', false,
        'settlement_id', v_existing_settlement,
        'payout_done', v_payout_done,
        'reason', 'already_exists'
      );
    end if;
    raise;
end;
$function$;

comment on function public.accept_custom_order_deliverable_atomic(uuid, uuid, boolean) is
  'P1+P0: Student deliverable accept — order completed + settlement + mentor escrow payout in one transaction. service_role only.';

revoke all on function public.accept_custom_order_deliverable_atomic(uuid, uuid, boolean) from public;
grant execute on function public.accept_custom_order_deliverable_atomic(uuid, uuid, boolean) to service_role;


-- ===== 056_p0_custom_order_escrow_refund.sql =====

-- P0: 맞춤의뢰 에스크로 3단계 — 예치 전액 학생 반환(취소·환불) + 관리자 환불 연동
-- 선행: 054(record_custom_order_escrow_hold), 055(record_custom_order_escrow_payout), 030(approve_refund_request_admin)
-- idempotent: CREATE OR REPLACE
--
-- 호출: service_role 전용. authenticated/anon GRANT 금지.
-- 멱등키: cr_refund_{order_id}
-- reason: custom_order_escrow_refund

-- ---------------------------------------------------------------------------
-- record_custom_order_escrow_refund
-- ---------------------------------------------------------------------------
create or replace function public.record_custom_order_escrow_refund(
  p_order_id uuid
)
returns void
language plpgsql
security definer
set search_path = public
as $function$
declare
  o public.custom_request_orders%rowtype;
  s public.custom_order_settlement_items%rowtype;
  v_hold_idem text := 'cr_hold_' || p_order_id::text;
  v_payout_idem text := 'cr_payout_' || p_order_id::text;
  v_refund_idem text := 'cr_refund_' || p_order_id::text;
  v_hold_cents bigint;
  v_pay text;
  v_norm text;
  v_new_ledger_id uuid;
  v_wu int;
  v_now timestamptz := now();
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;

  select * into o
  from public.custom_request_orders
  where id = p_order_id
  for update;

  if not found then
    raise exception 'ORDER_NOT_FOUND';
  end if;

  if o.student_id is null then
    raise exception 'STUDENT_NOT_FOUND';
  end if;

  v_pay := lower(trim(coalesce(nullif(trim(o.payment_status), ''), '')));
  v_norm := public._order_primary_status_norm(o);

  -- 멘토 지급 완료 차단: payout ledger 또는 settlement paid
  if exists (
    select 1 from public.cash_ledger l
    where l.idempotency_key = v_payout_idem
      and l.reason = 'custom_order_escrow_payout'
  ) then
    raise exception 'ALREADY_PAID_OUT';
  end if;

  select * into s
  from public.custom_order_settlement_items
  where custom_request_order_id = p_order_id
  for update;

  if found and s.status = 'paid' then
    raise exception 'ALREADY_PAID_OUT';
  end if;

  -- 멱등: 이미 환불 ledger 있으면 상태만 수리 후 종료
  if exists (
    select 1 from public.cash_ledger l
    where l.idempotency_key = v_refund_idem
      and l.reason = 'custom_order_escrow_refund'
  ) then
    if v_pay = 'escrowed' then
      update public.custom_request_orders
      set payment_status = 'refunded', updated_at = v_now
      where id = p_order_id;
    end if;

    update public.custom_order_settlement_items
    set status = 'cancelled', updated_at = v_now
    where custom_request_order_id = p_order_id
      and status in ('pending', 'on_hold', 'payable');

    if v_norm not in ('cancelled', 'canceled', 'refunded') then
      update public.custom_request_orders
      set
        status = 'cancelled',
        state = 'cancelled',
        order_status = 'cancelled',
        updated_at = v_now
      where id = p_order_id;
    end if;

    return;
  end if;

  -- hold 필수
  select abs(l.delta_cents) into v_hold_cents
  from public.cash_ledger l
  where l.idempotency_key = v_hold_idem
    and l.reason = 'custom_order_escrow_hold'
  limit 1;

  if v_hold_cents is null then
    raise exception 'ESCROW_HOLD_MISSING';
  end if;

  if v_hold_cents <= 0 or v_hold_cents > 1000000000 then
    raise exception 'ESCROW_HOLD_AMOUNT_INVALID';
  end if;

  -- 환불 대상: escrowed(정상) 또는 refunded(부분 실패 수리)
  if v_pay not in ('escrowed', 'refunded') then
    raise exception 'PAYMENT_NOT_ESCROWED';
  end if;

  insert into public.cash_ledger (user_id, delta_cents, reason, ref_type, ref_id, idempotency_key)
  values (
    o.student_id,
    v_hold_cents,
    'custom_order_escrow_refund',
    'custom_request_orders',
    p_order_id,
    v_refund_idem
  )
  on conflict (idempotency_key) do nothing
  returning id into v_new_ledger_id;

  if v_new_ledger_id is null then
    return;
  end if;

  insert into public.cash_wallets (user_id, balance_cents)
  values (o.student_id, 0)
  on conflict (user_id) do nothing;

  update public.cash_wallets w
  set balance_cents = w.balance_cents + v_hold_cents
  where w.user_id = o.student_id;
  get diagnostics v_wu = row_count;
  if coalesce(v_wu, 0) = 0 then
    raise exception 'CASH_WALLET_UPDATE_FAILED' using errcode = 'P0001';
  end if;

  update public.custom_order_settlement_items
  set status = 'cancelled', updated_at = v_now
  where custom_request_order_id = p_order_id
    and status in ('pending', 'on_hold', 'payable');

  update public.custom_request_orders
  set
    payment_status = 'refunded',
    status = 'cancelled',
    state = 'cancelled',
    order_status = 'cancelled',
    updated_at = v_now
  where id = p_order_id;
end;
$function$;

comment on function public.record_custom_order_escrow_refund(uuid) is
  'P0: Custom order escrow refund — return hold to student wallet (append-only). Blocks paid-out orders. service_role only.';

revoke all on function public.record_custom_order_escrow_refund(uuid) from public;
revoke all on function public.record_custom_order_escrow_refund(uuid) from anon;
revoke all on function public.record_custom_order_escrow_refund(uuid) from authenticated;

grant execute on function public.record_custom_order_escrow_refund(uuid) to service_role;

-- ---------------------------------------------------------------------------
-- approve_refund_request_admin — 맞춤의뢰 예치 주문은 escrow refund 경로(이중 credit 방지)
-- ---------------------------------------------------------------------------
create or replace function public.approve_refund_request_admin(
  p_refund_id uuid,
  p_admin_id uuid,
  p_admin_note text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $function$
declare
  r public.refunds%rowtype;
  v_amount bigint;
  v_settlement_status text;
  v_idem text := 'refund_credit:' || p_refund_id::text;
  v_ledger_id uuid;
  v_existing_delta bigint;
  v_wu int;
  v_admin_ok boolean;
  v_hold_cents bigint;
  v_escrow_refund boolean := false;
begin
  if p_refund_id is null then
    return jsonb_build_object('ok', false, 'message', '환불 ID가 필요합니다.');
  end if;
  if p_admin_id is null then
    return jsonb_build_object('ok', false, 'message', '관리자 ID가 필요합니다.');
  end if;

  select exists(
    select 1 from public.users u where u.id = p_admin_id and u.role = 'admin'
  ) into v_admin_ok;
  if not coalesce(v_admin_ok, false) then
    raise exception 'ADMIN_REQUIRED';
  end if;

  select * into r from public.refunds where id = p_refund_id for update;
  if not found then
    return jsonb_build_object('ok', false, 'message', '환불 요청을 찾을 수 없습니다.');
  end if;

  if r.status is distinct from 'pending' then
    return jsonb_build_object(
      'ok', true,
      'noop', true,
      'refund_id', p_refund_id,
      'message', '이미 처리되었거나 대기 상태가 아닙니다.',
      'status', r.status
    );
  end if;

  if r.custom_request_order_id is not null then
    select s.status into v_settlement_status
    from public.custom_order_settlement_items s
    where s.custom_request_order_id = r.custom_request_order_id
    limit 1;
    if found and v_settlement_status = 'paid' then
      return jsonb_build_object(
        'ok', false,
        'message', '이미 정산 지급이 완료된 건은 자동 환불할 수 없습니다. 수동 조정이 필요합니다.'
      );
    end if;

    if exists (
      select 1 from public.cash_ledger l
      where l.idempotency_key = 'cr_payout_' || r.custom_request_order_id::text
        and l.reason = 'custom_order_escrow_payout'
    ) then
      return jsonb_build_object(
        'ok', false,
        'message', '이미 정산 지급이 완료된 건은 자동 환불할 수 없습니다. 수동 조정이 필요합니다.'
      );
    end if;

    select abs(l.delta_cents) into v_hold_cents
    from public.cash_ledger l
    where l.idempotency_key = 'cr_hold_' || r.custom_request_order_id::text
      and l.reason = 'custom_order_escrow_hold'
    limit 1;

    if v_hold_cents is not null then
      v_escrow_refund := true;
      begin
        perform public.record_custom_order_escrow_refund(r.custom_request_order_id);
      exception
        when others then
          if sqlerrm like '%ALREADY_PAID_OUT%' or sqlerrm like '%ESCROW_HOLD_MISSING%' then
            return jsonb_build_object('ok', false, 'message', '이미 정산 지급이 완료된 건은 자동 환불할 수 없습니다. 수동 조정이 필요합니다.');
          end if;
          if sqlerrm like '%PAYMENT_NOT_ESCROWED%' then
            return jsonb_build_object('ok', false, 'message', '예치(에스크로) 상태가 아니어서 예치 반환을 할 수 없습니다.');
          end if;
          raise;
      end;
      v_amount := v_hold_cents;
    end if;
  end if;

  if not v_escrow_refund then
    if r.amount_cents is null or r.amount_cents <= 0 then
      raise exception '환불 금액이 설정되지 않아 자동 승인할 수 없습니다.';
    end if;

    v_amount := r.amount_cents;

    if v_amount > 1000000000 then
      return jsonb_build_object('ok', false, 'message', '환불 금액이 허용 한도를 초과합니다.');
    end if;

    if r.custom_request_order_id is not null then
      update public.custom_order_settlement_items s
      set status = 'cancelled', updated_at = now()
      where s.custom_request_order_id = r.custom_request_order_id
        and s.status in ('pending', 'on_hold', 'payable');
    end if;

    insert into public.cash_ledger (
      user_id, delta_cents, reason, ref_type, ref_id, idempotency_key
    )
    values (
      r.user_id, v_amount, 'refund_approved', 'refunds', r.id, v_idem
    )
    on conflict (idempotency_key) do nothing
    returning id into v_ledger_id;

    if v_ledger_id is null then
      select cl.delta_cents into v_existing_delta
      from public.cash_ledger cl
      where cl.idempotency_key = v_idem
      limit 1;
      if not found then
        raise exception 'REFUND_LEDGER_IDEMPOTENT_MISS' using errcode = 'P0001';
      end if;
      if v_existing_delta is distinct from v_amount then
        raise exception 'REFUND_LEDGER_AMOUNT_MISMATCH' using errcode = 'P0001';
      end if;
    end if;

    if v_ledger_id is not null then
      insert into public.cash_wallets (user_id, balance_cents)
      values (r.user_id, 0)
      on conflict (user_id) do nothing;

      update public.cash_wallets w
      set balance_cents = w.balance_cents + v_amount
      where w.user_id = r.user_id;
      get diagnostics v_wu = row_count;
      if coalesce(v_wu, 0) = 0 then
        raise exception 'CASH_WALLET_UPDATE_FAILED' using errcode = 'P0001';
      end if;
    end if;

    if r.custom_request_order_id is not null then
      update public.custom_request_orders o
      set payment_status = 'refunded', updated_at = now()
      where o.id = r.custom_request_order_id;
    end if;
  end if;

  update public.refunds
  set
    status = 'succeeded',
    processed_at = now(),
    processed_by = p_admin_id,
    admin_note = p_admin_note,
    updated_at = now()
  where id = r.id;

  if r.payment_id is not null then
    update public.payments p
    set status = 'refunded', updated_at = now()
    where p.id = r.payment_id;
  end if;

  if r.payment_id is not null then
    update public.subscriptions s
    set status = 'canceled', updated_at = now()
    where s.payment_id = r.payment_id
      and s.status is distinct from 'canceled';
  end if;

  return jsonb_build_object(
    'ok', true,
    'noop', false,
    'refund_id', r.id,
    'ledger_inserted', case when v_escrow_refund then true else (v_ledger_id is not null) end,
    'escrow_refund', v_escrow_refund,
    'amount_cents', v_amount,
    'message', '환불이 승인되었습니다.'
  );
end;
$function$;

comment on function public.approve_refund_request_admin(uuid, uuid, text) is
  'P0: Admin refund approve — custom order escrow uses record_custom_order_escrow_refund (no refund_credit double pay). service_role only.';

revoke all on function public.approve_refund_request_admin(uuid, uuid, text) from public;
revoke all on function public.approve_refund_request_admin(uuid, uuid, text) from anon;
revoke all on function public.approve_refund_request_admin(uuid, uuid, text) from authenticated;
grant execute on function public.approve_refund_request_admin(uuid, uuid, text) to service_role;


-- ===== 057_p0_custom_order_dispute_split.sql =====

-- P0: 맞춤의뢰 에스크로 4단계-A — 분쟁 예치 분배(멘토 gross·학생 환불, 20% 공제)
-- 선행: 054(hold), 055(payout), 056(refund), 043(_order_primary_status_norm), 004(disputes)
-- idempotent: CREATE OR REPLACE
--
-- 호출: service_role 전용. authenticated/anon GRANT 금지.
-- 멱등키: cr_dispute_payout_{order_id}, cr_dispute_refund_{order_id}
-- reason: custom_order_dispute_payout | custom_order_dispute_refund
-- 플랫폼 수수료분: 별도 platform wallet ledger 없음 — hold 차감분에 implicit(055/056 동일).

-- ---------------------------------------------------------------------------
-- record_custom_order_dispute_split
-- ---------------------------------------------------------------------------
create or replace function public.record_custom_order_dispute_split(
  p_order_id uuid,
  p_mentor_gross_won integer,
  p_student_refund_won integer,
  p_admin_id uuid
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $function$
declare
  o public.custom_request_orders%rowtype;
  s public.custom_order_settlement_items%rowtype;
  v_hold_idem text := 'cr_hold_' || p_order_id::text;
  v_payout_idem text := 'cr_payout_' || p_order_id::text;
  v_refund_idem text := 'cr_refund_' || p_order_id::text;
  v_dispute_payout_idem text := 'cr_dispute_payout_' || p_order_id::text;
  v_dispute_refund_idem text := 'cr_dispute_refund_' || p_order_id::text;
  v_hold_cents bigint;
  v_hold_gross_won integer;
  v_settlement_gross integer;
  v_fee_rate numeric := 0.20;
  v_platform_fee_won integer;
  v_mentor_net_won integer;
  v_mentor_cents bigint;
  v_student_cents bigint;
  v_pay text;
  v_norm text;
  v_admin_ok boolean;
  v_new_mentor_ledger uuid;
  v_new_student_ledger uuid;
  v_wu int;
  v_now timestamptz := now();
  v_disputes_resolved int := 0;
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if p_admin_id is null then
    raise exception 'ADMIN_REQUIRED';
  end if;
  if p_mentor_gross_won is null or p_student_refund_won is null then
    raise exception 'DISPUTE_SPLIT_AMOUNTS_REQUIRED';
  end if;
  if p_mentor_gross_won < 0 or p_student_refund_won < 0 then
    raise exception 'DISPUTE_SPLIT_AMOUNTS_INVALID';
  end if;

  select exists(
    select 1 from public.users u where u.id = p_admin_id and u.role = 'admin'
  ) into v_admin_ok;
  if not coalesce(v_admin_ok, false) then
    raise exception 'ADMIN_REQUIRED';
  end if;

  select * into o
  from public.custom_request_orders
  where id = p_order_id
  for update;

  if not found then
    raise exception 'ORDER_NOT_FOUND';
  end if;

  if o.student_id is null or o.mentor_id is null then
    raise exception 'ORDER_PARTIES_MISSING';
  end if;

  v_pay := lower(trim(coalesce(nullif(trim(o.payment_status), ''), '')));
  v_norm := public._order_primary_status_norm(o);

  -- payout / refund / dispute-split 상호 배타
  if exists (
    select 1 from public.cash_ledger l
    where l.idempotency_key = v_payout_idem
      and l.reason = 'custom_order_escrow_payout'
  ) then
    raise exception 'ALREADY_PAID_OUT';
  end if;

  if exists (
    select 1 from public.cash_ledger l
    where l.idempotency_key = v_refund_idem
      and l.reason = 'custom_order_escrow_refund'
  ) then
    raise exception 'ALREADY_REFUNDED';
  end if;

  select * into s
  from public.custom_order_settlement_items
  where custom_request_order_id = p_order_id
  for update;

  if found and s.status = 'paid' then
    raise exception 'ALREADY_PAID_OUT';
  end if;

  select abs(l.delta_cents) into v_hold_cents
  from public.cash_ledger l
  where l.idempotency_key = v_hold_idem
    and l.reason = 'custom_order_escrow_hold'
  limit 1;

  if v_hold_cents is null then
    raise exception 'ESCROW_HOLD_MISSING';
  end if;

  if v_hold_cents <= 0 or v_hold_cents > 1000000000 then
    raise exception 'ESCROW_HOLD_AMOUNT_INVALID';
  end if;

  if v_hold_cents % 100 <> 0 then
    raise exception 'ESCROW_HOLD_AMOUNT_INVALID';
  end if;

  v_hold_gross_won := (v_hold_cents / 100)::integer;

  if found then
    v_settlement_gross := s.gross_amount;
    if v_settlement_gross is distinct from v_hold_gross_won then
      raise exception 'ESCROW_HOLD_AMOUNT_MISMATCH';
    end if;
  end if;

  -- 멱등: 분배 ledger 가 하나라도 있으면 상태 수리 후 종료
  if exists (
    select 1 from public.cash_ledger l
    where l.idempotency_key in (v_dispute_payout_idem, v_dispute_refund_idem)
      and l.reason in ('custom_order_dispute_payout', 'custom_order_dispute_refund')
  ) then
    update public.custom_order_settlement_items
    set status = 'cancelled', updated_at = v_now
    where custom_request_order_id = p_order_id
      and status in ('pending', 'on_hold', 'payable');

    update public.custom_request_orders
    set
      payment_status = 'dispute_resolved',
      status = 'dispute_resolved',
      state = 'dispute_resolved',
      order_status = 'dispute_resolved',
      updated_at = v_now
    where id = p_order_id;

    update public.disputes d
    set
      status = 'resolved',
      resolved_at = coalesce(d.resolved_at, v_now),
      resolved_by = coalesce(d.resolved_by, p_admin_id),
      updated_at = v_now
    where d.custom_request_order_id = p_order_id
      and d.status in ('open', 'under_review', 'escalated');

    get diagnostics v_disputes_resolved = row_count;

    return jsonb_build_object(
      'ok', true,
      'noop', true,
      'order_id', p_order_id,
      'hold_gross_won', v_hold_gross_won,
      'disputes_resolved', v_disputes_resolved
    );
  end if;

  if p_mentor_gross_won + p_student_refund_won is distinct from v_hold_gross_won then
    raise exception 'DISPUTE_SPLIT_MISMATCH';
  end if;

  if v_pay not in ('escrowed', 'dispute_resolved') then
    raise exception 'PAYMENT_NOT_ESCROWED';
  end if;

  v_platform_fee_won := floor(p_mentor_gross_won * v_fee_rate)::integer;
  v_mentor_net_won := p_mentor_gross_won - v_platform_fee_won;
  v_mentor_cents := v_mentor_net_won::bigint * 100;
  v_student_cents := p_student_refund_won::bigint * 100;

  if v_mentor_cents > 1000000000 or v_student_cents > 1000000000 then
    raise exception 'p_amount_too_large';
  end if;

  if v_mentor_cents > 0 then
    insert into public.cash_ledger (user_id, delta_cents, reason, ref_type, ref_id, idempotency_key)
    values (
      o.mentor_id,
      v_mentor_cents,
      'custom_order_dispute_payout',
      'custom_request_orders',
      p_order_id,
      v_dispute_payout_idem
    )
    on conflict (idempotency_key) do nothing
    returning id into v_new_mentor_ledger;

    if v_new_mentor_ledger is not null then
      insert into public.cash_wallets (user_id, balance_cents)
      values (o.mentor_id, 0)
      on conflict (user_id) do nothing;

      update public.cash_wallets w
      set balance_cents = w.balance_cents + v_mentor_cents
      where w.user_id = o.mentor_id;
      get diagnostics v_wu = row_count;
      if coalesce(v_wu, 0) = 0 then
        raise exception 'CASH_WALLET_UPDATE_FAILED' using errcode = 'P0001';
      end if;
    end if;
  end if;

  if v_student_cents > 0 then
    insert into public.cash_ledger (user_id, delta_cents, reason, ref_type, ref_id, idempotency_key)
    values (
      o.student_id,
      v_student_cents,
      'custom_order_dispute_refund',
      'custom_request_orders',
      p_order_id,
      v_dispute_refund_idem
    )
    on conflict (idempotency_key) do nothing
    returning id into v_new_student_ledger;

    if v_new_student_ledger is not null then
      insert into public.cash_wallets (user_id, balance_cents)
      values (o.student_id, 0)
      on conflict (user_id) do nothing;

      update public.cash_wallets w
      set balance_cents = w.balance_cents + v_student_cents
      where w.user_id = o.student_id;
      get diagnostics v_wu = row_count;
      if coalesce(v_wu, 0) = 0 then
        raise exception 'CASH_WALLET_UPDATE_FAILED' using errcode = 'P0001';
      end if;
    end if;
  end if;

  update public.custom_order_settlement_items
  set status = 'cancelled', updated_at = v_now
  where custom_request_order_id = p_order_id
    and status in ('pending', 'on_hold', 'payable');

  update public.custom_request_orders
  set
    payment_status = 'dispute_resolved',
    status = 'dispute_resolved',
    state = 'dispute_resolved',
    order_status = 'dispute_resolved',
    updated_at = v_now
  where id = p_order_id;

  update public.disputes d
  set
    status = 'resolved',
    resolved_at = coalesce(d.resolved_at, v_now),
    resolved_by = coalesce(d.resolved_by, p_admin_id),
    updated_at = v_now
  where d.custom_request_order_id = p_order_id
    and d.status in ('open', 'under_review', 'escalated');

  get diagnostics v_disputes_resolved = row_count;

  return jsonb_build_object(
    'ok', true,
    'noop', false,
    'order_id', p_order_id,
    'hold_gross_won', v_hold_gross_won,
    'mentor_gross_won', p_mentor_gross_won,
    'mentor_platform_fee_won', v_platform_fee_won,
    'mentor_net_won', v_mentor_net_won,
    'mentor_cents', v_mentor_cents,
    'student_refund_won', p_student_refund_won,
    'student_cents', v_student_cents,
    'fee_rate', v_fee_rate,
    'disputes_resolved', v_disputes_resolved
  );
end;
$function$;

comment on function public.record_custom_order_dispute_split(uuid, integer, integer, uuid) is
  'P0: Custom order dispute escrow split — mentor net (gross−20%) + student refund; hold gross must match sum. service_role only.';

revoke all on function public.record_custom_order_dispute_split(uuid, integer, integer, uuid) from public;
revoke all on function public.record_custom_order_dispute_split(uuid, integer, integer, uuid) from anon;
revoke all on function public.record_custom_order_dispute_split(uuid, integer, integer, uuid) from authenticated;

grant execute on function public.record_custom_order_dispute_split(uuid, integer, integer, uuid) to service_role;


-- ===== 058_mentor_student_nickname_rpc.sql =====

-- =============================================================================
-- P0: 멘토 맞춤의뢰 화면 — 의뢰자 닉네임/이름 표시용 RPC
--  • users SELECT RLS(users_select_own)는 본인만 → 멘토가 학생 users 직접 SELECT 불가.
--  • SECURITY DEFINER + custom_request_orders(mentor_id = auth.uid()) 연결 student_id 만 반환.
--  • 반환: id, nickname, full_name (이메일 등 미포함). 관계 없는 student_id 는 0행.
--  • 호출: authenticated 멘토. staging·운영 적용 전 SQL Editor에서 점검.
--  • **이미 Supabase 적용됨 — 기록용.**
-- =============================================================================

create or replace function public.get_mentor_student_nicknames(p_student_ids uuid[])
returns table (
  id uuid,
  nickname text,
  full_name text
)
language sql
stable
security definer
set search_path = public
as $$
  select
    u.id,
    u.nickname,
    u.full_name
  from public.users u
  where p_student_ids is not null
    and array_length(p_student_ids, 1) is not null
    and u.id = any (p_student_ids)
    and (select auth.uid()) is not null
    and exists (
      select 1
      from public.custom_request_orders o
      where o.mentor_id = (select auth.uid())
        and o.student_id = u.id
    );
$$;

revoke all on function public.get_mentor_student_nicknames(uuid[]) from public;
grant execute on function public.get_mentor_student_nicknames(uuid[]) to authenticated;

comment on function public.get_mentor_student_nicknames(uuid[]) is
  'P0 멘토: 본인 맞춤의뢰 주문에 연결된 학생 id[] 에 대한 nickname·full_name(표시용).';


-- ===== 059_p0_custom_request_application_attachments_storage.sql =====

-- P0: 멘토 지원서 포트폴리오 첨부 — private Storage + custom_request_application_attachments + storage.objects RLS
-- 선행: 001( users ), 003( custom_request_posts / custom_request_applications ), is_admin()
-- 012( post 첨부 )와 버킷/정책명 분리. RLS 주의: post는 mentor 전원 read — 본 테이블은 **지원 멘토 본인 + post 작성 학생 + admin** 만 read.
-- idempotent

-- ---------------------------------------------------------------------------
-- 1) custom_request_application_attachments
-- ---------------------------------------------------------------------------
create table if not exists public.custom_request_application_attachments (
  id uuid primary key default gen_random_uuid(),
  application_id uuid not null references public.custom_request_applications (id) on delete cascade,
  uploaded_by uuid not null references public.users (id) on delete restrict,
  storage_path text not null,
  original_filename text not null,
  mime_type text,
  file_size_bytes bigint,
  created_at timestamptz not null default now()
);

comment on table public.custom_request_application_attachments is
  '멘토 지원서 제출 시 올린 포트폴리오/참고 파일 메타. storage_path 는 ASCII 키(버킷 내부), 표시명은 original_filename.';

create index if not exists idx_craa_application_created
  on public.custom_request_application_attachments (application_id, created_at asc);

alter table public.custom_request_application_attachments enable row level security;

-- ---------------------------------------------------------------------------
-- 2) Helper — application → post 작성자(학생) 확인 (012 post 작성자 동의어)
-- ---------------------------------------------------------------------------
create or replace function public.user_is_post_author_for_craa_application(p_application_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $f$
  select exists (
    select 1
    from public.custom_request_applications a
    join public.custom_request_posts p on p.id = a.post_id
    where a.id = p_application_id
      and (
        p.author_id = (select auth.uid())
        or p.student_id = (select auth.uid())
        or p.user_id = (select auth.uid())
        or p.requester_id = (select auth.uid())
        or p.client_id = (select auth.uid())
      )
  );
$f$;

create or replace function public.user_is_application_mentor_for_craa_application(p_application_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $f$
  select exists (
    select 1
    from public.custom_request_applications a
    where a.id = p_application_id
      and a.mentor_id = (select auth.uid())
  );
$f$;

-- ---------------------------------------------------------------------------
-- 3) 테이블 RLS — INSERT: 지원 멘토 본인 / SELECT: 멘토 본인 · post 작성 학생 · admin (mentor 전원 read 금지)
-- ---------------------------------------------------------------------------
drop policy if exists "craa_insert_mentor" on public.custom_request_application_attachments;
create policy "craa_insert_mentor"
  on public.custom_request_application_attachments
  for insert
  to authenticated
  with check (
    uploaded_by = (select auth.uid())
    and public.user_is_application_mentor_for_craa_application(application_id) = true
  );

drop policy if exists "craa_select_authorized" on public.custom_request_application_attachments;
create policy "craa_select_authorized"
  on public.custom_request_application_attachments
  for select
  to authenticated
  using (
    (select public.is_admin()) = true
    or public.user_is_application_mentor_for_craa_application(application_id) = true
    or public.user_is_post_author_for_craa_application(application_id) = true
  );

-- ---------------------------------------------------------------------------
-- 4) Storage bucket (private) — 012와 동일 20MB / MIME
-- ---------------------------------------------------------------------------
insert into storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
values (
  'custom-request-application-attachments',
  'custom-request-application-attachments',
  false,
  20971520,
  array[
    'application/pdf',
    'image/png',
    'image/jpeg',
    'image/webp',
    'application/zip',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'application/vnd.openxmlformats-officedocument.presentationml.presentation'
  ]::text[]
)
on conflict (id) do update set
  public = excluded.public,
  file_size_limit = coalesce(excluded.file_size_limit, storage.buckets.file_size_limit),
  allowed_mime_types = coalesce(excluded.allowed_mime_types, storage.buckets.allowed_mime_types);

-- ---------------------------------------------------------------------------
-- 5) Path → application UUID(첫 세그먼트) + storage.objects RLS
--    경로: {applicationId}/{timestamp}-{8hex}.{ext}
-- ---------------------------------------------------------------------------
create or replace function public.craa_application_uuid_from_path(p_name text)
returns uuid
language plpgsql
immutable
security definer
set search_path = public
as $f$
begin
  return nullif(split_part(p_name, '/', 1), '')::uuid;
exception
  when others then
    return null;
end;
$f$;

create or replace function public.user_is_application_mentor_for_craa_path(p_name text)
returns boolean
language sql
stable
security definer
set search_path = public
as $f$
  select public.user_is_application_mentor_for_craa_application(
    public.craa_application_uuid_from_path(p_name)
  );
$f$;

create or replace function public.user_can_read_craa_storage_path(p_name text)
returns boolean
language sql
stable
security definer
set search_path = public
as $f$
  select
    (select public.is_admin()) = true
    or public.user_is_application_mentor_for_craa_path(p_name) = true
    or public.user_is_post_author_for_craa_application(
      public.craa_application_uuid_from_path(p_name)
    ) = true;
$f$;

drop policy if exists "craa_storage_read_authorized" on storage.objects;
create policy "craa_storage_read_authorized"
  on storage.objects
  for select
  to authenticated
  using (
    bucket_id = 'custom-request-application-attachments'
    and public.user_can_read_craa_storage_path(name)
  );

drop policy if exists "craa_storage_insert_mentor" on storage.objects;
create policy "craa_storage_insert_mentor"
  on storage.objects
  for insert
  to authenticated
  with check (
    bucket_id = 'custom-request-application-attachments'
    and public.user_is_application_mentor_for_craa_path(name) = true
  );

